import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma DMMF field to its TypeScript type string, including list notation.
 */
export function prismaTypeToTs(field: DMMF.Field): string {
  let tsType: string

  if (field.kind === 'object') {
    tsType = field.type
  } else {
    switch (field.type) {
      case 'String':
        tsType = 'string'
        break
      case 'Int':
      case 'Float':
      case 'Decimal':
        tsType = 'number'
        break
      case 'BigInt':
        tsType = 'bigint'
        break
      case 'Boolean':
        tsType = 'boolean'
        break
      case 'DateTime':
        tsType = 'Date'
        break
      case 'Json':
        tsType = 'unknown'
        break
      case 'Bytes':
        tsType = 'Uint8Array'
        break
      default:
        // Enum or unsupported native type — use the PSL type name directly.
        tsType = field.type
    }
  }

  return field.isList ? `${tsType}[]` : tsType
}

/**
 * Renders a TypeScript interface for a Prisma model, covering all non-relation fields.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => `  ${f.name}${f.isRequired ? '' : '?'}: ${prismaTypeToTs(f)}`)
    .join('\n')

  return `export interface ${model.name} {\n${lines}\n}`
}

/**
 * Renders a TypeScript interface for model create input.
 *
 * Auto-generated and read-only fields are omitted; fields with defaults are optional.
 */
export function renderCreateInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue
      return `  ${f.name}${optional ? '?' : ''}: ${prismaTypeToTs(f)}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${lines}\n}`
}

/**
 * Renders a TypeScript interface for model update input.
 *
 * All fields are optional since a PATCH only needs the fields to change.
 */
export function renderUpdateInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
    .map((f) => `  ${f.name}?: ${prismaTypeToTs(f)}`)
    .join('\n')

  return `export interface ${model.name}UpdateInput {\n${lines}\n}`
}

/**
 * Renders a TypeScript interface capturing the unique-lookup fields for a model
 * (i.e. its `@id` and `@unique` scalar fields).
 */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const lines = model.fields
    .filter((f) => (f.isId || f.isUnique) && f.kind !== 'object')
    .map((f) => `  ${f.name}?: ${prismaTypeToTs(f)}`)
    .join('\n')

  return `export interface ${model.name}WhereUniqueInput {\n${lines}\n}`
}

/**
 * Converts a PascalCase model name to the camelCase path segment used in REST URLs.
 */
export function toApiPath(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1)
}

/**
 * Renders the typed REST client class for a single Prisma model with CRUD methods.
 *
 * The generated class targets a conventional REST API where:
 *   GET    /{model}            → findMany
 *   GET    /{model}/unique?… → findUnique
 *   POST   /{model}            → create
 *   PATCH  /{model}/unique?…  → update
 *   DELETE /{model}/unique?…  → delete
 */
export function renderModelClient(model: DMMF.Model): string {
  const { name } = model
  const path = toApiPath(name)

  return `export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const query = params ? '?' + new URLSearchParams(params as Record<string, string>).toString() : ''
    const response = await fetch(\`\${this.baseUrl}/${path}\${query}\`)
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.baseUrl}/${path}/unique?\${params}\`)
    if (response.status === 404) return null
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.baseUrl}/${path}/unique?\${params}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.baseUrl}/${path}/unique?\${params}\`, {
      method: 'DELETE',
    })
    if (!response.ok) throw new RestClientError(response.status, await response.text())
    return response.json() as Promise<${name}>
  }
}
`
}

