import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import {
  renderCreateInput,
  renderModelClient,
  renderModelInterface,
  renderUpdateInput,
  renderWhereUniqueInput,
  toApiPath,
} from './template'

const GENERATED_FILE_HEADER = `\
// This file was auto-generated by @prisma/generator-rest-client.
// Do not edit it manually — re-run the generator to update.
/* eslint-disable */
// @ts-nocheck
`

const REST_CLIENT_ERROR_CLASS = `
/**
 * Thrown when the REST API returns a non-2xx status code.
 */
export class RestClientError extends Error {
  constructor(
    public readonly statusCode: number,
    public readonly body: string,
  ) {
    super(\`REST client error \${statusCode}: \${body}\`)
    this.name = 'RestClientError'
  }
}
`

/**
 * Resolves the output directory from generator config, falling back to a
 * sibling `generated/rest-client` directory next to the schema file.
 */
function resolveOutputDir(options: GeneratorOptions): string {
  const value = options.generator.output?.value
  if (value) return value
  return path.join(path.dirname(options.schemaPath), 'generated', 'rest-client')
}

/**
 * Renders the root `RestClient` class that exposes one typed sub-client per model.
 */
function renderRootClient(modelNames: readonly string[]): string {
  const properties = modelNames
    .map((name) => `  readonly ${toApiPath(name)}: ${name}Client`)
    .join('\n')

  const initializers = modelNames
    .map((name) => `    this.${toApiPath(name)} = new ${name}Client(baseUrl)`)
    .join('\n')

  return `
/**
 * Top-level REST client. Instantiate with your API base URL and access each
 * model's typed methods as properties, e.g. \`client.user.findMany()\`.
 */
export class RestClient {
${properties}

  constructor(baseUrl: string) {
${initializers}
  }
}
`
}

/**
 * Generates the complete contents of `rest-client.ts` from the DMMF document
 * embedded in the generator options.
 */
export function generateRestClient(options: GeneratorOptions): string {
  const { models } = options.dmmf.datamodel
  const modelNames = models.map((m) => m.name)

  const sections: string[] = [
    GENERATED_FILE_HEADER,
    REST_CLIENT_ERROR_CLASS,
    models.map(renderModelInterface).join('\n\n'),
    models.map(renderCreateInput).join('\n\n'),
    models.map(renderUpdateInput).join('\n\n'),
    models.map(renderWhereUniqueInput).join('\n\n'),
    models.map(renderModelClient).join('\n'),
    renderRootClient(modelNames),
  ]

  return sections.join('\n')
}

/**
 * Writes `rest-client.ts` to the configured output directory, creating it if
 * it does not already exist.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)

  await fs.promises.mkdir(outputDir, { recursive: true })

  const content = generateRestClient(options)
